package genxsolution.vms.vmsbackend.maintenance_management.maintenance_record.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_record.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_record.service.MaintenanceRecordService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/vehicles/maintenance-records") public class MaintenanceRecordController { private final MaintenanceRecordService service; public MaintenanceRecordController(MaintenanceRecordService service){this.service=service;} @GetMapping public List<MaintenanceRecordResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public MaintenanceRecordResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public MaintenanceRecordResponse create(@RequestBody MaintenanceRecordUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public MaintenanceRecordResponse update(@PathVariable UUID id,@RequestBody MaintenanceRecordUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
